// Selecciona leads que esperan chat y AUN no tienen telefono.
const items = $input.all();
const out = [];
const now = Date.now();
const MAX_MS = 48 * 60 * 60 * 1000; // 48h: tras esto se marca sin_whatsapp

for (const it of items) {
  const r = it.json || {};
  const tel = (r.telefono || '').toString().trim();
  const estado = (r.estado || '').toString().trim();
  const pendiente = !tel && (estado === 'esperando_chat' || estado === 'chat_iniciado');
  if (!pendiente) continue;
  if (!r.kommo_lead_id) continue;
  const ts = Date.parse(r.timestamp);
  const ageMs = isNaN(ts) ? 0 : (now - ts);
  out.push({ json: {
    kommo_lead_id: String(r.kommo_lead_id),
    ref_code: r.ref_code || '',
    expirado: ageMs > MAX_MS
  }});
}
return out;

const base = $('Filtrar pendientes').item.json;
const lead = $json || {};
const contactos = (lead._embedded && lead._embedded.contacts) || [];
contactos.sort((a, b) => (b.is_main === true) - (a.is_main === true));
const contactId = contactos.length ? String(contactos[0].id) : '';
return [{ json: { kommo_lead_id: base.kommo_lead_id, ref_code: base.ref_code, expirado: base.expirado, contactId } }];

const base = $('Elegir contacto barrido').item.json;
const contact = $json || {};

function normalizar(raw) {
  if (raw === null || raw === undefined) return '';
  let d = String(raw).replace(/[^\d]/g, '');
  if (d.length < 10) return '';
  if (!d.startsWith('58') && d.length === 10) d = '58' + d;
  return d;
}

let telefono = '';
const campos = contact.custom_fields_values || [];
for (const f of campos) {
  if (f.field_code === 'PHONE' || f.field_type === 'phone') {
    for (const v of (f.values || [])) {
      const t = normalizar(v.value);
      if (t) { telefono = t; break; }
    }
  }
  if (telefono) break;
}

if (telefono) {
  return [{ json: { kommo_lead_id: base.kommo_lead_id, telefono, kommo_contact_id: base.contactId || '', estado: 'chat_iniciado' } }];
}
// Sin telefono y ya paso la ventana de 48h -> estado terminal para no reintentar por siempre.
if (base.expirado) {
  return [{ json: { kommo_lead_id: base.kommo_lead_id, telefono: '', kommo_contact_id: base.contactId || '', estado: 'sin_whatsapp' } }];
}
// Aun dentro de la ventana: seguir esperando, no escribir nada.
return [];
